const required = ['WHATSAPP_PHONE_ID', 'UPI_ID', 'RESTAURANT_NAME', 'MAX_TABLES', 'TAX_RATE', 'WHATSAPP_APP_SECRET', 'GROQ_API_KEY', 'TWILIO_ACCOUNT_SID', 'TWILIO_PHONE', 'KITCHEN_PHONE', 'SUPPORT_EMAIL', 'SUPPORT_PHONE', 'OPENING_TIME', 'CLOSING_TIME', 'TIMEZONE', 'ALLERGEN_KEYWORDS', 'PRIVACY_POLICY_VERSION', 'OPENING_TIME', 'CLOSING_TIME', 'TIMEZONE', 'ALLERGEN_KEYWORDS', 'PRIVACY_POLICY_VERSION', 'OPENING_TIME', 'CLOSING_TIME', 'TIMEZONE', 'ALLERGEN_KEYWORDS', 'PRIVACY_POLICY_VERSION'];
const missing = required.filter(v => !$env[v]);
if (missing.length > 0) throw new Error(`Missing env vars: ${missing.join(', ')}`);
const taxRate = parseFloat($env.TAX_RATE);
if (isNaN(taxRate) || taxRate < 0 || taxRate > 100) throw new Error('TAX_RATE must be 0-100');
const maxTables = parseInt($env.MAX_TABLES);
if (isNaN(maxTables) || maxTables < 1) throw new Error('MAX_TABLES must be positive');

const crypto = require('crypto');
// Verify WhatsApp Webhook Signature
try {
  const secret = $env.WHATSAPP_APP_SECRET || '';
  const headers = $request?.headers || {};
  const signature = headers['x-hub-signature-256'];

  if (signature && secret) {
      const payloadStr = JSON.stringify($input.item.json);
      const expectedSig = 'sha256=' + crypto.createHmac('sha256', secret).update(payloadStr).digest('hex');

      if (signature !== expectedSig) {
          console.log('HMAC Error - Expected:', expectedSig, 'Got:', signature);
          throw new Error('Invalid Signature / Unauthorized Webhook Request');
      }
  }
} catch (e) {
  throw new Error('Validation failed: ' + e.message);
}

const entry = $input.item.json.entry?.[0];
if (!entry?.changes?.[0]?.value) throw new Error('Invalid webhook payload');
return $input.item.json;

const phone = ($input.item.json.from || '').toString();
const phoneRegex = /^[+\d-]+$/;
if (!phoneRegex.test(phone)) if (action && action.startsWith('CMD_ADD_')) text = action.replace('CMD_ADD_', '') + ' ' + text;\nreturn [{json: {...$input.item.json, error: 'INVALID_PHONE', error_msg: 'Invalid phone format'}}];
if (phone.length > 20) return [{json: {...$input.item.json, error: 'PHONE_TOO_LONG', error_msg: 'Phone too long'}}];
const raw = ($input.item.json.raw_text || '').toUpperCase();
let text = raw.replace(/[^A-Z0-9_\s]/g, ' ').replace(/\s+/g, ' ').trim();
const action = ($input.item.json.button_id || $input.item.json.list_id || '').toUpperCase();
return [{json: {...$input.item.json, text, action, timestamp: Date.now()}}];

const items = $input.all();
if (!items || items.length < 2) throw new Error('Missing input data for session processing');
const inputData = items.find(i => i.json.from) || items[0];
const dbResult = items.find(i => i.json.phone) || {};
const phone = inputData.json.from;
const now = Date.now();
let session = {phone, table_number: null, cart: [], customer_name: inputData.json.contact_name, last_seen: now, session_started: now, total_orders: 0, preferences: {}};
if (dbResult.json && dbResult.json.phone) {
  let cart = [];
  let preferences = {};
  try { cart = JSON.parse(dbResult.json.cart || '[]'); if (!Array.isArray(cart)) cart = []; } catch (e) { cart = []; }
  try { preferences = JSON.parse(dbResult.json.preferences || '{}'); if (typeof preferences !== 'object') preferences = {}; } catch (e) { preferences = {}; }
  const lastSeen = new Date(dbResult.json.last_seen).getTime();
  const expired = isNaN(lastSeen) || (now - lastSeen) > 900000;
  if (!expired) {
    session = {...dbResult.json, cart, preferences, last_seen: now};
  } else {
    session.total_orders = dbResult.json.total_orders || 0;
  }
}
session.is_returning = (dbResult.json && parseInt(dbResult.json.total_orders) > 0);
return [{json: {...inputData.json, session, is_new_session: !dbResult.json || !dbResult.json.phone}}];

